import React, { useState, useEffect, useRef } from "react";
import Papa from "papaparse";
import "./First.css";

function First() {

  const accessColumns = [
    { emp: "EMP_C-RET(SUB)", log: "LOG_C-RET(SUB)", badge: "BADGE_C-RET(SUB)", name: "C-RET SUB" },
    { emp: "EMP_RECEIVE_EACH", log: "LOG_RECEIVE_EACH", badge: "BADGE_RECEIVE_EACH", name: "RECEIVE EACH" },
    { emp: "EMP_CUBIC _SCAN", log: "LOG_CUBIC _SCAN", badge: "BADGE_CUBIC_SCAN", name: "CUBIC SCAN" },
    { emp: "EMP_RECEIVE_PALLET", log: "LOG_RECEIVE_PALLET", badge: "BADGE_RECEIVE_PALLET", name: "RECEIVE PALLET" },
    { emp: "EMP_C-RET_STOW", log: "LOG_C-RET_STOW", badge: "BADGE_C-RET_STOW", name: "C-RET STOW" },
    { emp: "EMP_PACK_MANUAL_SLAM", log: "LOG_PACK_MANUAL_SLAM", badge: "BADGE_PACK_MANUAL_SLAM", name: "PACK MANUAL SLAM(slammer)" },
    { emp: "EMP_ICQA", log: "LOG_ICQA", badge: "BADGE_ICQA", name: "ICQA" },
    { emp: "EMP_V-RET_PACK", log: "LOG_V-RET_PACK", badge: "BADGE_V-RET_PACK", name: "V-RET PACK" },
    { emp: "EMP_STOW", log: "LOG_STOW", badge: "BADGE_STOW", name: "STOW" },
    { emp: "EMP_PICK", log: "LOG_PICK", badge: "BADGE_PICK", name: "PICK" },
    { emp: "EMP_PACK_SLAM", log: "LOG_PACK_SLAM", badge: "BADGE_PACK_SLAM", name: "PACK SLAM" },
    { emp: "EMP_PACK MULTIS", log: "LOG_PACK_MULTIS", badge: "BADGE_PACK_MULTIS", name: "PACK MULTIS" },
    { emp: "EMP_REBIN", log: "LOG_REBIN", badge: "BADGE_REBIN", name: "REBIN" },
    { emp: "EMP_TOTE WRANGLER", log: "LOG_TOTE WRANGLER", badge: "BADGE_TOTE_WRANGLER", name: "TOTE WRANGLER" },
    { emp: "EMP_PACK_SINGLES", log: "LOG_PACK_SINGLES", badge: "BADGE_PACK_SINGLES", name: "PACK SINGLES" },

  ];

  const [employees, setEmployees] = useState([]);
  const [input, setInput] = useState("");
  const [results, setResults] = useState([]);
  const [notFound, setNotFound] = useState([]);
  const [selectedAccess, setSelectedAccess] = useState("");
  const [loading, setLoading] = useState(true);

  const inputRef = useRef();

  // 🚀 LOAD GOOGLE SHEET DATA
  useEffect(() => {
    Papa.parse(
      "https://docs.google.com/spreadsheets/d/e/2PACX-1vQCSgffPIAdGfMyc4OaG1slvhyOz078XBMf3hx0K5T8AO5cLMpP7u9fzLPJZrrx6Ov4_Bjtqf-wGItW/pub?gid=516228192&single=true&output=csv",
      {
        download: true,
        header: true,
        skipEmptyLines: true,

        complete: (result) => {
          processData(result.data);
          setLoading(false);
        },

        error: (err) => {
          console.error("CSV Load Error:", err);
          setLoading(false);
        }
      }
    );
  }, []);

  // 🧠 PROCESS DATA
  const processData = (rawData) => {
    let temp = {};

    rawData.forEach(row => {
      accessColumns.forEach(col => {

        let employeeId = (row[col.emp] || "").trim().toLowerCase();
        let logId = (row[col.log] || "").trim().toLowerCase();
        let badgeId = (row[col.badge] || "").trim().toLowerCase();

        if (!employeeId || !logId || !badgeId) return;

        const key = `${employeeId}_${logId}_${badgeId}`;

        if (!temp[key]) {
          temp[key] = {
            employeeId,
            logId,
            badgeId,
            access: new Set()
          };
        }

        temp[key].access.add(col.name);
      });
    });

    const finalData = Object.values(temp).map(item => ({
      employeeId: item.employeeId,
      logId: item.logId,
      badgeId: item.badgeId,
      access: Array.from(item.access).sort().join(", ")
    }));

    setEmployees(finalData);
  };

  // 🔍 SEARCH FUNCTION
  const handleSearch = () => {
    if (!input.trim()) return;

    const values = input.toLowerCase().split(/[\s,]+/).filter(Boolean);

    let found = [];
    let notFoundItems = [];

    values.forEach(val => {
      const match = employees.find(emp =>
        emp.employeeId === val ||
        emp.logId === val ||
        emp.badgeId === val
      );

      if (match) found.push(match);
      else notFoundItems.push(val);
    });

    setResults(prev => {
      const updated = [...prev];

      found.forEach(item => {
        const exists = updated.some(
          e =>
            e.employeeId === item.employeeId &&
            e.logId === item.logId &&
            e.badgeId === item.badgeId
        );

        if (!exists) updated.push(item);
      });

      return updated;
    });

    setNotFound(prev => [...new Set([...prev, ...notFoundItems])]);

    setInput("");
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter") handleSearch();
  };

  // FILTER
  const filteredResults = selectedAccess
    ? results.filter(emp => emp.access.includes(selectedAccess))
    : results;

  const uniqueAccess = [...new Set(accessColumns.map(a => a.name))];

  // CLEAR
  const clearSearch = () => {
    setInput("");
    setResults([]);
    setNotFound([]);
  };

  return (
    <div className="dashboard-card">
      <h2 className="dashboard-title">Employee Access</h2>

      <div className="controls">

        <input
          ref={inputRef}
          className="input"
          type="text"
          placeholder="Emp ID / Log ID / Badge ID"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
        />

        <button className="button" onClick={handleSearch}>Add</button>
        <button className="button" onClick={clearSearch}>Clear</button>

        <select
          className="select"
          value={selectedAccess}
          onChange={(e) => setSelectedAccess(e.target.value)}
        >
          <option value="">All Access</option>
          {uniqueAccess.map((a, i) => (
            <option key={i}>{a}</option>
          ))}
        </select>
      </div>

      <div className="total-row">
        Total Count: {filteredResults.length}
      </div>

      {loading && <div className="loading">Loading Live Data... ⏳</div>}

      {notFound.length > 0 && (
        <div className="not-found-box">
          <strong>Not Found:</strong> {notFound.join(", ")}
        </div>
      )}

      {filteredResults.length > 0 && (
        <table className="dashboard-table">
          <thead>
            <tr>
              <th>Employee ID</th>
              <th>Log ID</th>
              <th>Badge ID</th>
              <th>Access</th>
            </tr>
          </thead>

          <tbody>
            {filteredResults.map((emp, index) => (
              <tr key={index}>
                <td>{emp.employeeId}</td>
                <td>{emp.logId}</td>
                <td>{emp.badgeId}</td>
                <td>{emp.access}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default First;